func filterClass(current, filter string) string {
	if current == filter {
		return "bg-indigo-100 text-indigo-700 font-medium"
	}
	return "bg-gray-100 text-gray-600 hover:bg-gray-200"
}

func paginationURL(projectID int, status string, page int) string {
	base := fmt.Sprintf("/projects/%d/transfer-dcs?page=%d", projectID, page)
	if status != "" {
		base += "&status=" + status
	}
	return base
}

